import React from 'react'
import { useCMS } from '../../contexts/CMSContext'

interface SectionLockControlProps {
    locked: boolean | undefined
    onToggle: (newLocked: boolean) => void
}

const SectionLockControl: React.FC<SectionLockControlProps> = ({ locked, onToggle }) => {
    const { isSuperAdminMode } = useCMS()

    if (!isSuperAdminMode) return null

    return (
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
            <span style={{ fontSize: '12px', fontWeight: 600, color: '#666', textTransform: 'uppercase' }}>
                {locked ? 'LOCKED' : 'UNLOCKED'}
            </span>
            <label className="news-toggle-control" style={{ marginBottom: 0 }}>
                <input
                    type="checkbox"
                    checked={!locked}
                    onChange={() => onToggle(!locked)}
                />
                <span className="news-toggle-slider"></span>
            </label>
        </div>
    )
}

export default SectionLockControl
