import React, { useState } from 'react'
import './SupportEditor.css'
import { SupportContent, SupportColumn, SupportItem } from '../../contexts/types'
import ImageEditor from './ImageEditor'
import SectionLockControl from './SectionLockControl'
import { STATIC_VIDEOS } from '../../contexts/db/videos'
import { STATIC_MUSIC_ALBUMS } from '../../contexts/db/music-albums'
import { STATIC_COLLECTIONS } from '../../contexts/db/collections'

type SupportEditorProps = {
    data: SupportContent
    onChange: (data: Partial<SupportContent>) => void
}

const resolveEditorThumbnail = (item: SupportItem, type: string, isFeatured: boolean) => {
    if (item.image) {
        // Remove WordPress size suffixes from custom images too
        return item.image.replace(/-(\d+)x(\d+)(\.[a-z0-9]+)$/i, '$3');
    }
    
    if (type === 'tv') {
        if (item.videoId) {
            return isFeatured 
               ? `https://img.youtube.com/vi/${item.videoId}/maxresdefault.jpg`
               : `https://img.youtube.com/vi/${item.videoId}/mqdefault.jpg`;
        }
        const found = STATIC_VIDEOS.find(v => String(v.id) === String(item.id) || (v as any).slug === item.slug);
        if (found?.videoId) {
            return isFeatured 
               ? `https://img.youtube.com/vi/${found.videoId}/maxresdefault.jpg`
               : `https://img.youtube.com/vi/${found.videoId}/mqdefault.jpg`;
        }
    }
    
    if (type === 'music') {
        const tracks = STATIC_MUSIC_ALBUMS.flatMap((a: any) => a.tracks || []);
        const found = tracks.find(t => String(t.id) === String(item.id) || (t as any).slug === item.slug);
        if (found) {
            if ((found as any).image) return (found as any).image.replace(/-(\d+)x(\d+)(\.[a-z0-9]+)$/i, '$3');
            if ((found as any).imageFile) return `https://bodephatquoc.org/wp-content/uploads/${(found as any).imageFile}`;
        }
    }
    
    if (type === 'support') {
        const found = STATIC_COLLECTIONS.find(c => String(c.id) === String(item.id) || (c as any).slug === item.slug);
        if (found) {
            if ((found as any).image) return (found as any).image.replace(/-(\d+)x(\d+)(\.[a-z0-9]+)$/i, '$3');
            if ((found as any).body) {
                const html = (found as any).body;
                // 1. Try anchor href first (high res)
                const hrefMatch = html.match(/<a[^>]+href=["']([^"']+\.(?:jpg|jpeg|png|gif|webp))["']/i);
                if (hrefMatch) return hrefMatch[1].replace(/-(\d+)x(\d+)(\.[a-z0-9]+)$/i, '$3');

                // 2. img src fallback
                const match = html.match(/<img[^>]+src="([^">]+)"/);
                if (match) {
                    return match[1].replace(/-(\d+)x(\d+)(\.[a-z0-9]+)$/i, '$3');
                }
            }
        }
    }
    
    return null;
}

const SupportEditor: React.FC<SupportEditorProps> = ({ data, onChange }) => {
    const [editingColumnId, setEditingColumnId] = useState<string | null>(null)

    const updateColumn = (colId: string, updates: Partial<SupportColumn>) => {
        const updatedColumns = data.columns.map(col =>
            col.id === colId ? { ...col, ...updates } : col
        )
        onChange({ columns: updatedColumns })
    }

    const updateItem = (colId: string, itemId: string, updates: Partial<SupportItem>) => {
        const column = data.columns.find(c => c.id === colId)
        if (!column) return

        const updatedItems = column.items.map(item =>
            item.id === itemId ? { ...item, ...updates } : item
        )
        updateColumn(colId, { items: updatedItems })
    }

    const addItem = (colId: string) => {
        const column = data.columns.find(c => c.id === colId)
        if (!column) return

        const newItem: SupportItem = {
            id: `item-${Date.now()}`,
            title: 'New Title',
            image: ''
        }
        updateColumn(colId, { items: [...column.items, newItem] })
    }

    const removeItem = (colId: string, itemId: string) => {
        const column = data.columns.find(c => c.id === colId)
        if (!column) return

        const updatedItems = column.items.filter(item => item.id !== itemId)
        updateColumn(colId, { items: updatedItems })
    }

    return (
        <div className="support-editor">
            <div className="editor-header-title">
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <h2>Edit Dharma Support</h2>
                    <SectionLockControl locked={data.locked} onToggle={(locked) => onChange({ locked })} />
                </div>
                <p className="editor-subtitle">Manage columns and items for the support section</p>
            </div>

            <div className={`editor-form ${data.locked ? 'locked-section' : ''}`} style={data.locked ? { pointerEvents: 'none', opacity: 0.6 } : {}}>
                <div className="form-group">
                    <label className="form-label">Section Main Title</label>
                    <textarea
                        className="form-input"
                        rows={2}
                        value={data.sectionTitle}
                        onChange={(e) => onChange({ sectionTitle: e.target.value })}
                        placeholder="Use \n for line breaks"
                    />
                </div>

                <div className="form-grid-2">
                    <ImageEditor
                        label="Desktop Background"
                        value={data.backgroundImage}
                        onChange={(url) => onChange({ backgroundImage: url })}
                        aspectRatio="landscape"
                    />
                    <ImageEditor
                        label="Mobile Background"
                        value={data.mobileBackgroundImage}
                        onChange={(url) => onChange({ mobileBackgroundImage: url })}
                        aspectRatio="landscape"
                    />
                </div>

                <div className="columns-list">
                    {data.columns.map((column, colIdx) => (
                        <div key={column.id} className={`column-card ${editingColumnId === column.id ? 'active' : ''}`}>
                            <div className="column-card-header">
                                <span className="item-label">{column.title || 'Untitled Column'}</span>
                                <button
                                    className="btn-action edit"
                                    onClick={() => setEditingColumnId(editingColumnId === column.id ? null : column.id)}
                                >
                                    {editingColumnId === column.id ? 'Close' : 'Edit'}
                                </button>
                            </div>

                            {editingColumnId === column.id && (
                                <div className="column-item-editor">
                                    <div className="form-group">
                                        <label className="form-label">Column Title</label>
                                        <input
                                            type="text"
                                            className={`form-input ${column.title.length > 60 ? 'input-error' : ''}`}
                                            value={column.title}
                                            onChange={(e) => updateColumn(column.id, { title: e.target.value })}
                                        />
                                        <div className="input-counter">
                                            <span className={column.title.length > 60 ? 'text-danger' : ''}>
                                                {column.title.length}/60
                                            </span>
                                            {column.title.length > 60 && <span className="warning-text"> — Too long</span>}
                                        </div>
                                    </div>

                                    <div className="items-section">
                                        <div className="sub-section-header">
                                            <h4>Column Items</h4>
                                            <button className="btn-mini-add" onClick={() => addItem(column.id)}>+ Add Item</button>
                                        </div>

                                        <div className="items-list-editor" style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                                            {column.items.map((item, itemIdx) => {
                                                const isTV = column.id === 'tv';
                                                const isMusic = column.id === 'music';
                                                const isGallery = column.id === 'support';
                                                const isFeatured = isTV && itemIdx === 0;

                                                const handleDatabaseSelect = (e: React.ChangeEvent<HTMLSelectElement>) => {
                                                    const val = e.target.value;
                                                    if (!val) return;

                                                    if (isTV) {
                                                        const found = STATIC_VIDEOS.find(v => String(v.id) === val || (v as any).slug === val);
                                                        if (found) {
                                                            updateItem(column.id, item.id, { 
                                                                title: String(found.title),
                                                                videoId: found.videoId,
                                                                id: String(found.id),
                                                                slug: (found as any).slug || String(found.id),
                                                                image: '' // Clear custom image to use YouTube auto thumb
                                                            });
                                                        }
                                                    } else if (isMusic) {
                                                        const tracks = STATIC_MUSIC_ALBUMS.flatMap((a: any) => a.tracks || []);
                                                        const found = tracks.find(t => String(t.id) === val || (t as any).slug === val);
                                                        if (found) {
                                                            updateItem(column.id, item.id, { 
                                                                title: (found as any).title || (found as any).name || '',
                                                                id: String(found.id),
                                                                slug: (found as any).slug || String(found.id),
                                                                image: '' // Use database thumb
                                                            });
                                                        }
                                                    } else if (isGallery) {
                                                        const found = STATIC_COLLECTIONS.find(c => String(c.id) === val || (c as any).slug === val);
                                                        if (found) {
                                                            updateItem(column.id, item.id, { 
                                                                title: (found as any).title || '',
                                                                id: String(found.id),
                                                                slug: (found as any).slug || String(found.id),
                                                                image: '' // Use database thumb
                                                            });
                                                        }
                                                    }
                                                };

                                                return (
                                                    <div key={item.id} className={`item-edit-card ${isFeatured ? 'featured-item-edit' : ''}`} style={{ padding: '1.5rem', border: isFeatured ? '2px solid #E6B422' : '1px solid #eee' }}>
                                                        {isFeatured && <div style={{ fontSize: '10px', background: '#E6B422', color: 'white', padding: '2px 8px', borderRadius: '4px', alignSelf: 'flex-start', marginBottom: '8px', fontWeight: 'bold' }}>FEATURED / TRỌNG TÂM</div>}
                                                        
                                                        {/* Database Picker */}
                                                        <div className="form-group" style={{ marginBottom: '1.5rem' }}>
                                                            <label className="form-label mini" style={{ color: '#E6B422', fontWeight: 600 }}>TÁC DANH (CHỌN TỪ DATABASE DƯỚI ĐÂY)</label>
                                                            <select 
                                                                className="form-input mini" 
                                                                onChange={handleDatabaseSelect} 
                                                                value=""
                                                            >
                                                                <option value="">-- Chọn nội dung từ cơ sở dữ liệu --</option>
                                                                {isTV && STATIC_VIDEOS.map(v => (
                                                                    <option key={v.id} value={(v as any).slug || v.id}>{String(v.title).substring(0, 60)}...</option>
                                                                ))}
                                                                {isMusic && STATIC_MUSIC_ALBUMS.flatMap(a => a.tracks || []).map(t => (
                                                                    <option key={t.id} value={(t as any).slug || t.id}>{(t as any).title || (t as any).name}</option>
                                                                ))}
                                                                {isGallery && STATIC_COLLECTIONS.map(c => (
                                                                    <option key={c.id} value={(c as any).slug || c.id}>{(c as any).title}</option>
                                                                ))}
                                                            </select>
                                                        </div>

                                                        <div style={{ display: 'grid', gridTemplateColumns: '120px 1fr', gap: '1.5rem' }}>
                                                            <div className="item-thumb-edit">
                                                                <ImageEditor
                                                                    label="Custom Image"
                                                                    value={item.image}
                                                                    onChange={(url) => updateItem(column.id, item.id, { image: url })}
                                                                    aspectRatio="landscape"
                                                                    compact={true}
                                                                />
                                                                {(() => {
                                                                    const thumb = resolveEditorThumbnail(item, column.id, isFeatured);
                                                                    if (thumb) {
                                                                        return (
                                                                            <div style={{ marginTop: '10px', padding: '5px', background: '#f8f9fa', borderRadius: '4px', border: '1px solid #ddd' }}>
                                                                                <div style={{ fontSize: '9px', fontWeight: 'bold', color: '#666', marginBottom: '4px', textTransform: 'uppercase' }}>Preview / Xem Trước</div>
                                                                                <img src={thumb} alt="Preview" style={{ width: '100%', display: 'block', borderRadius: '2px', border: '1px solid #eee' }} />
                                                                                {!item.image && <div style={{ fontSize: '8px', fontStyle: 'italic', color: '#888', marginTop: '3px' }}>Từ Database/YouTube</div>}
                                                                            </div>
                                                                        )
                                                                    }
                                                                    return null;
                                                                })()}
                                                            </div>
                                                            <div className="item-fields" style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                                                                <div className="form-group" style={{ gridColumn: '1 / -1' }}>
                                                                    <label className="form-label mini">Title</label>
                                                                    <input
                                                                        type="text"
                                                                        className="form-input mini"
                                                                        style={{ fontWeight: 600 }}
                                                                        value={item.title}
                                                                        onChange={(e) => updateItem(column.id, item.id, { title: e.target.value })}
                                                                    />
                                                                </div>

                                                                {isTV && (
                                                                    <div className="form-group">
                                                                        <label className="form-label mini">YouTube Video ID</label>
                                                                        <input
                                                                            type="text"
                                                                            className="form-input mini"
                                                                            value={item.videoId || ''}
                                                                            onChange={(e) => updateItem(column.id, item.id, { videoId: e.target.value })}
                                                                            placeholder="e.g. WbmkvEtRoDk"
                                                                        />
                                                                    </div>
                                                                )}

                                                                {(isMusic || isGallery) && (
                                                                    <div className="form-group">
                                                                        <label className="form-label mini">ID / Slug</label>
                                                                        <input
                                                                            type="text"
                                                                            className="form-input mini"
                                                                            value={item.slug || item.id || ''}
                                                                            onChange={(e) => updateItem(column.id, item.id, { id: e.target.value, slug: e.target.value })}
                                                                        />
                                                                    </div>
                                                                )}

                                                                <div className="form-group">
                                                                    <label className="form-label mini">Custom Link (optional)</label>
                                                                    <input
                                                                        type="text"
                                                                        className="form-input mini"
                                                                        value={item.link || ''}
                                                                        onChange={(e) => updateItem(column.id, item.id, { link: e.target.value })}
                                                                        placeholder="e.g. /custom-page"
                                                                    />
                                                                </div>

                                                                <div style={{ gridColumn: '1 / -1', display: 'flex', justifyContent: 'flex-end', marginTop: '10px' }}>
                                                                    <button className="btn-mini-delete" onClick={() => removeItem(column.id, item.id)} title="Delete Item">
                                                                        × Remove Item
                                                                    </button>
                                                                </div>
                                                            </div>
                                                        </div>
                                                    </div>
                                                );
                                            })}
                                        </div>
                                    </div>
                                </div>
                            )}
                        </div>
                    ))}
                </div>
            </div>
        </div>
    )
}

export default SupportEditor
